from pico_ioc import component, intercepted_by
from config import StoreSettings
from interceptors import AuditInterceptor

@component
class PaymentGateway:
    def charge(self, amount: float) -> str:
        return f"Charged ${amount:.2f}"

@component
class OrderService:
    def __init__(self, gateway: PaymentGateway, settings: StoreSettings):
        self._gateway = gateway
        self._settings = settings

    @intercepted_by(AuditInterceptor)
    def place_order(self, amount: float) -> str:
        total = amount * (1 + self._settings.tax_rate)
        return f"{self._settings.name}: {self._gateway.charge(total)}"
